+                .await
+            {
+                Outcome::Ok(1) => {}
+                other => panic!("insert in tx failed: {other:?}"),
+            }
+            drop(tx);
+
+            let rows = match conn.query(&cx, "SELECT COUNT(*) FROM t", &[]).await {
+                Outcome::Ok(rows) => rows,
+                other => panic!("count query failed: {other:?}"),
+            };
+            assert_eq!(rows[0].get_idx(0).unwrap().as_integer(), Some(0));
+        });
+    }
